    SCAN_STATE_NOT_PROCESSED = 'SCAN_STATE_NOT_PROCESSED'
    SCAN_STATE_IDLE = 'SCAN_STATE_IDLE'
    SCAN_STATE_INGESTING = 'SCAN_STATE_INGESTING'
    SCAN_STATE_ANALYTIC = 'SCAN_STATE_ANALYTIC'
